"use strict";parserFactory.register("freewebnovel.com",()=>new FreeWebNovelComParser),parserFactory.register("bednovel.com",()=>new FreeWebNovelParser),parserFactory.register("innnovel.com",()=>new FreeWebNovelParser),parserFactory.register("libread.com",()=>new FreeWebNovelParser),parserFactory.register("novellive.com",()=>new NovelliveParser),parserFactory.register("novellive.app",()=>new NovelliveParser),parserFactory.register("novellive.net",()=>new NovelliveParser),parserFactory.register("readwn.org",()=>new NovelliveParser);class FreeWebNovelParser extends Parser{constructor(){super(),this.minimumThrottle=1e3}async getChapterUrls(e){let r=e.querySelector("ul#idData");return util.hyperlinksToChapterList(r)}extractTitleImpl(e){return e.querySelector("h1.tit")}extractAuthor(e){return e.querySelector("[title=Author]").parentNode.querySelector("a").textContent}extractSubject(e){return[...e.querySelector("[title=Genre]").parentNode.querySelectorAll("a")].map(e=>e.textContent.trim()).join(", ")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.pic")}findChapterTitle(e){return e.querySelector("span.chapter")}findContent(e){return e.querySelector("div.txt")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.inner")]}}class NovelliveParser extends FreeWebNovelParser{constructor(){super()}async getChapterUrls(e,r){return this.getChapterUrlsFromMultipleTocPages(e,this.extractPartialChapterList,this.getUrlsOfTocPages,r)}getUrlsOfTocPages(e){let r=[...e.querySelectorAll(".page a.index-container-btn")]?.pop()?.href,t=[];if(r){let e=r.lastIndexOf("/"),l=r.substring(e+1),o=parseInt(l);if(!isNaN(o)){let l=r.substring(0,e+1);for(let e=2;e<=o;++e)t.push(l+e)}}return t}extractPartialChapterList(e){return[...e.querySelector(".m-newest2").querySelectorAll("ul li a")].map(e=>util.hyperLinkToChapter(e))}}class FreeWebNovelComParser extends FreeWebNovelParser{constructor(){super()}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"p sub"),super.removeUnwantedElementsFromContentElement(e)}}